10ŌåÆ/**
11ŌåÆ * Read stdin using platform-specific approach.
12ŌåÆ * Returns empty string if stdin is a TTY or unavailable.
13ŌåÆ */
14ŌåÆexport async function readStdin(): Promise<string> {
15ŌåÆ	if (process.stdin.isTTY) {
16ŌåÆ		return "";
17ŌåÆ	}
18ŌåÆ
19ŌåÆ	const chunks: Buffer[] = [];
20ŌåÆ	try {
21ŌåÆ		for await (const chunk of process.stdin) {
22ŌåÆ			chunks.push(Buffer.from(chunk));
23ŌåÆ		}
24ŌåÆ	} catch (error: unknown) {
25ŌåÆ		const code = (error as { code?: string }).code;
26ŌåÆ		if (code === "EBADF" || code === "ENXIO") {
27ŌåÆ			return "";
28ŌåÆ		}
29ŌåÆ		throw error;
30ŌåÆ	}
31ŌåÆ	return Buffer.concat(chunks).toString("utf8");
32ŌåÆ}
