 1ŌåÆimport { mkdir, unlink, writeFile } from "node:fs/promises";
 2ŌåÆimport { homedir } from "node:os";
 3ŌåÆimport { join } from "node:path";
 4ŌåÆimport { exec } from "./exec.js";
 5ŌåÆimport { SESSION_TAGS, type SessionTag } from "./types.js";
 6ŌåÆ
 7ŌåÆconst SYSTEM_PROMPT = `You are a session classifier. Analyze the Claude Code session transcript and classify it into exactly ONE of these categories:
 8ŌåÆ
 9ŌåÆ- research: Exploring codebase, understanding code, answering questions about how things work
10ŌåÆ- new_feature: Implementing new functionality or features
11ŌåÆ- bug_fix: Fixing bugs, errors, or unexpected behavior
12ŌåÆ- refactoring: Restructuring existing code without changing functionality
13ŌåÆ- documentation: Writing or updating documentation, comments, READMEs
14ŌåÆ- tests: Writing, updating, or fixing tests
15ŌåÆ
16ŌåÆCRITICAL: Respond with ONLY the tag name. Nothing else. No explanation, no punctuation, no formatting. Just ONE of: research, new_feature, bug_fix, refactoring, documentation, tests`;
17ŌåÆ
18ŌåÆ/**
19ŌåÆ * Classify a session transcript using Claude CLI.
20ŌåÆ * Returns one of the predefined tags based on the session content.
21ŌåÆ */
22ŌåÆexport async function classifySession(
23ŌåÆ	content: string,
24ŌåÆ): Promise<SessionTag | undefined> {
25ŌåÆ	// Truncate content to avoid excessive API costs
26ŌåÆ	const truncatedContent = content.slice(0, 50000);
27ŌåÆ
28ŌåÆ	const tempDir = join(homedir(), ".claude", "temp");
29ŌåÆ	const tempFile = join(tempDir, `classify-${Date.now()}.txt`);
30ŌåÆ
31ŌåÆ	try {
32ŌåÆ		await mkdir(tempDir, { recursive: true });
33ŌåÆ		await writeFile(
34ŌåÆ			tempFile,
35ŌåÆ			`Classify this session transcript:\n\n${truncatedContent}`,
36ŌåÆ		);
37ŌåÆ
38ŌåÆ		const prompt = `Read and classify the session transcript in this file: ${tempFile}`;
39ŌåÆ		const escapedPrompt = prompt.replace(/'/g, "'\\''");
40ŌåÆ		const escapedSystemPrompt = SYSTEM_PROMPT.replace(/'/g, "'\\''");
41ŌåÆ
42ŌåÆ		const result = await exec("sh", [
43ŌåÆ			"-c",
44ŌåÆ			`echo '${escapedPrompt}' | claude --output-format text --print --model haiku --no-session-persistence --dangerously-skip-permissions --system-prompt '${escapedSystemPrompt}'`,
45ŌåÆ		]);
46ŌåÆ
47ŌåÆ		if (result.exitCode !== 0) {
48ŌåÆ			return "other";
49ŌåÆ		}
50ŌåÆ
51ŌåÆ		const output = result.stdout.trim().toLowerCase();
52ŌåÆ
53ŌåÆ		// Exact match
54ŌåÆ		if (SESSION_TAGS.includes(output as SessionTag)) {
55ŌåÆ			return output as SessionTag;
56ŌåÆ		}
57ŌåÆ
58ŌåÆ		// Search for valid tags in verbose output
59ŌåÆ		for (const tag of SESSION_TAGS) {
60ŌåÆ			if (new RegExp(`\\b${tag}\\b`).test(output)) {
61ŌåÆ				return tag;
62ŌåÆ			}
63ŌåÆ		}
64ŌåÆ
65ŌåÆ		return "other";
66ŌåÆ	} catch {
67ŌåÆ		return undefined;
68ŌåÆ	} finally {
69ŌåÆ		try {
70ŌåÆ			await unlink(tempFile);
71ŌåÆ		} catch {
72ŌåÆ			// Ignore cleanup errors
73ŌåÆ		}
74ŌåÆ	}
75ŌåÆ}
